class SORTracker {
    private class Location implements Comparable<Location> {
        String name;
        int score;
        public Location(String name, int score) {
            this.name = name;
            this.score = score;
        }
        @Override
        public int compareTo(Location other) {
            if (this.score == other.score) {
                return this.name.compareTo(other.name);
            }
            return other.score - this.score;
        }
    }
    private java.util.PriorityQueue<Location> pq;
    private int queryCount;

    public SORTracker() {
        pq = new java.util.PriorityQueue<>();
        queryCount = 0;
    }

    public void add(String name, int score) {
        pq.add(new Location(name, score));
    }

    public String get() {
        queryCount++;
        int count = 0;
        java.util.PriorityQueue<Location> temp = new java.util.PriorityQueue<>();
        while (!pq.isEmpty()) {
            Location loc = pq.poll();
            count++;
            if (count == queryCount) {
                String result = loc.name;
                while (!temp.isEmpty()) {
                    pq.add(temp.poll());
                }
                pq.add(loc);
                return result;
            }
            temp.add(loc);
        }
        return "";
    }
}
